module reg_8bit(
    input clk,
    input load,
    input clear,
    input [7:0] data_in,
    output reg [7:0] data_out
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk) begin
    if (clear)
        data_out <= 8'b00000000;
    else if (load)
        data_out <= data_in;
end

endmodule
